 CREATE TABLE `meta_data2`.`enrolment_metadata` ( `id` varchar(33) NOT NULL ,  `date` int(11) DEFAULT NULL ,  `device` varchar(100) DEFAULT NULL ,  `center` varchar(100) DEFAULT NULL ,  `agent` varchar(100) DEFAULT NULL ,  `partner` varchar(100) DEFAULT NULL ,  `endtoendtime` int(11) DEFAULT NULL ,  `demotime` int(11) DEFAULT NULL ,  `pid` varchar(200) DEFAULT NULL ,  `cid` varchar(200) DEFAULT NULL ,  `tag` varchar(200) DEFAULT NULL ,  `uniqueid` varchar(200) DEFAULT NULL ,  `longitude` decimal(20,10) DEFAULT NULL ,  `latitude` decimal(20,10) DEFAULT NULL ,  `networktype` varchar(200) DEFAULT NULL ,  `capturemode` varchar(200) DEFAULT NULL ,  `networkstrength` varchar(200) DEFAULT NULL ,  `capturedate` int(11) DEFAULT NULL ,  `appname` varchar(200) DEFAULT NULL ,  `filename` varchar(200) DEFAULT NULL ,  `appid` varchar(200) DEFAULT NULL ,  `starttime` int(11) DEFAULT NULL ,  `endtime` int(11) DEFAULT NULL ,  `enrollmentusecase` varchar(200) DEFAULT NULL ,  `regcenter` varchar(200) DEFAULT NULL ,  `countryoforigin` varchar(200) DEFAULT NULL ,  `nationality` varchar(200) DEFAULT NULL ,  `locationgenerationtime` varchar(200) DEFAULT NULL ,  `fingerattempt` varchar(200) DEFAULT NULL ,  `photoattempt` varchar(200) DEFAULT NULL ,  `irisattempt` varchar(200) DEFAULT NULL ,  `demoattempt` varchar(200) DEFAULT NULL ,  `documentattempt` varchar(200) DEFAULT NULL ,  `signatureattempt` varchar(200) DEFAULT NULL ,  `previewattempt` varchar(200) DEFAULT NULL ,  `livenessattempt` varchar(200) DEFAULT NULL ,  `data` mediumtext DEFAULT NULL , `serial_num` int(11) NOT NULL, `creator_role` varchar(100) DEFAULT NULL, `created_source` varchar(100) DEFAULT NULL, `created_by` varchar(100) DEFAULT NULL, `creation_date` int(11) DEFAULT NULL, `modified_source` varchar(100) DEFAULT NULL, `modified_by` varchar(100) DEFAULT NULL, `modification_date` int(11) DEFAULT NULL, `ip_address` varchar(100) DEFAULT NULL, `device_id` text NOT NULL, `record_status` varchar(2) DEFAULT NULL ) ENGINE=InnoDB DEFAULT CHARSET=latin1 ; 
